const SOURCE = {
  wikipedia: (page) => ({
    sourceLabel: "Wikipedia",
    sourceUrl: `https://en.wikipedia.org/wiki/${encodeURIComponent(page.replaceAll(" ", "_"))}`,
  }),
  nasa: (slug) => ({ sourceLabel: "NASA Science", sourceUrl: `https://science.nasa.gov/${slug}` }),
  unesco: (slug) => ({ sourceLabel: "UNESCO", sourceUrl: `https://ich.unesco.org/en/RL/${slug}` }),
  fao: (slug) => ({ sourceLabel: "FAO GIAHS", sourceUrl: `https://www.fao.org/giahs/giahs-around-the-world/${slug}/en` }),
};

const legacyCategory = {
  "Living World": "Nature",
  "Planet Earth": "Nature",
  Cosmos: "Space",
  Matter: "Science",
  "Forces & Energy": "Science",
  "Numbers & Logic": "Science",
  Body: "Science",
  Mind: "Science",
  "Time & History": "History",
  Society: "Culture",
  Language: "Culture",
  "Belief & Ideas": "Culture",
  "Art & Expression": "Art",
  "Design & Technology": "Technology",
  "Food & Agriculture": "Culture",
};

function card(primaryDimension, id, page, question, teaser, imageAlt, secondaryDimensions = [], options = {}) {
  return {
    id,
    category: options.category ?? legacyCategory[primaryDimension],
    dimensions: [primaryDimension, ...secondaryDimensions],
    question,
    teaser,
    imageAlt,
    page,
    imageQuery: options.imageQuery ?? page,
    imageTitle: options.imageTitle,
    directImage: options.directImage,
    preferSearch: options.preferSearch ?? false,
    size: options.size ?? "standard",
    ...(options.source ?? SOURCE.wikipedia(page)),
  };
}

