const expectedDimensions = Object.keys(sections);
const all = expectedDimensions.flatMap((dimension) => sections[dimension]);
if (expectedDimensions.length !== 15) throw new Error(`Expected 15 dimensions, found ${expectedDimensions.length}.`);
for (const [dimension, cards] of Object.entries(sections)) {
  if (cards.length !== 10) throw new Error(`${dimension} has ${cards.length} cards; expected exactly 10.`);
}
if (new Set(all.map((item) => item.id)).size !== all.length) throw new Error("Candidate ids are not unique.");

const existingPath = valueAfter("--existing");
const existing = existingPath ? JSON.parse(await fs.readFile(existingPath, "utf8")) : [];
const existingIds = new Set(existing.map((item) => item.id));
const existingQuestions = new Set(existing.map((item) => normalize(item.question)));
const usedImages = new Set(existing.map((item) => canonicalImage(item.imageUrl)));
const imageCachePath = "/tmp/curiositypedia-deep-dive-image-cache.json";
const imageCache = new Map(Object.entries(await readJsonIfPresent(imageCachePath)));

for (const item of all) {
  if (existingIds.has(item.id)) throw new Error(`Existing catalog already contains ${item.id}.`);
  if (existingQuestions.has(normalize(item.question))) throw new Error(`Existing catalog already asks: ${item.question}`);
  if (item.dimensions.length > 4 || new Set(item.dimensions).size !== item.dimensions.length) {
    throw new Error(`${item.id} has invalid dimensions: ${item.dimensions.join(", ")}`);
  }
  const cached = imageCache.get(item.id);
  const cachedMatchesRequest = item.directImage
    ? cached?.url === item.directImage.url
    : !item.imageTitle || Boolean(cached && normalize(cached.title) === normalize(item.imageTitle));
  const image = cached && cachedMatchesRequest && isUsableImage(cached, usedImages, Boolean(item.imageTitle || item.directImage)) ? cached : await resolveImage(item, usedImages);
  item.imageUrl = image.url;
  item.imagePage = image.descriptionUrl;
  item.imageWidth = image.width;
  item.imageHeight = image.height;
  item.imageTitle = image.title;
  usedImages.add(canonicalImage(image.url));
  imageCache.set(item.id, image);
  await fs.writeFile(imageCachePath, `${JSON.stringify(Object.fromEntries(imageCache), null, 2)}\n`);
  process.stdout.write(`Resolved ${String(all.indexOf(item) + 1).padStart(3)}/${all.length}: ${item.id} -> ${image.title}\n`);
}

